1	// Package dex provides an embedded Dex OIDC identity provider.
2	package dex
3	
4	import (
5		"context"
6		"encoding/base64"
7		"errors"
8		"fmt"
9		"log/slog"
10		"net"
11		"net/http"
12		"os"
13		"path/filepath"
14		"strings"
15		"sync"
16		"time"
17	
18		dexapi "github.com/dexidp/dex/api/v2"
19		"github.com/dexidp/dex/server"
20		"github.com/dexidp/dex/storage"
21		"github.com/dexidp/dex/storage/sql"
22		"github.com/google/uuid"
23		"github.com/prometheus/client_golang/prometheus"
24		"golang.org/x/crypto/bcrypt"
25		"google.golang.org/grpc"
26	)
27	
28	// Config matches what management/internals/server/server.go expects
29	type Config struct {
30		Issuer  string
31		Port    int
32		DataDir string
33		DevMode bool
34	
35		// GRPCAddr is the address for the gRPC API (e.g., ":5557"). Empty disables gRPC.
36		GRPCAddr string
37	}
38	
39	// Provider wraps a Dex server
40	type Provider struct {
41		config       *Config
42		yamlConfig   *YAMLConfig
43		dexServer    *server.Server
44		httpServer   *http.Server
45		listener     net.Listener
46		grpcServer   *grpc.Server
47		grpcListener net.Listener
48		storage      storage.Storage
49		logger       *slog.Logger
50		mu           sync.Mutex
51		running      bool
52	}
53	
54	// NewProvider creates and initializes the Dex server
55	func NewProvider(ctx context.Context, config *Config) (*Provider, error) {
56		if config.Issuer == "" {
57			return nil, fmt.Errorf("issuer is required")
58		}
59		if config.Port <= 0 {
60			return nil, fmt.Errorf("invalid port")
61		}
62		if config.DataDir == "" {
63			return nil, fmt.Errorf("data directory is required")
64		}
65	
66		logger := slog.New(slog.NewTextHandler(os.Stderr, nil))
67	
68		// Ensure data directory exists
69		if err := os.MkdirAll(config.DataDir, 0700); err != nil {
70			return nil, fmt.Errorf("failed to create data directory: %w", err)
71		}
72	
73		// Initialize SQLite storage
74		dbPath := filepath.Join(config.DataDir, "oidc.db")
75		sqliteConfig := &sql.SQLite3{File: dbPath}
76		stor, err := sqliteConfig.Open(logger)
77		if err != nil {
78			return nil, fmt.Errorf("failed to open storage: %w", err)
79		}
80	
81		// Ensure a local connector exists (for password authentication)
82		if err := ensureLocalConnector(ctx, stor); err != nil {
83			stor.Close()
84			return nil, fmt.Errorf("failed to ensure local connector: %w", err)
85		}
86	
87		// Ensure issuer ends with /oauth2 for proper path mounting
88		issuer := strings.TrimSuffix(config.Issuer, "/")
89		if !strings.HasSuffix(issuer, "/oauth2") {
90			issuer += "/oauth2"
91		}
92	
93		// Build refresh token policy (required to avoid nil pointer panics)
94		refreshPolicy, err := server.NewRefreshTokenPolicy(logger, false, "", "", "")
95		if err != nil {
96			stor.Close()
97			return nil, fmt.Errorf("failed to create refresh token policy: %w", err)
98		}
99	
100		// Build Dex server config - use Dex's types directly
101		dexConfig := server.Config{
102			Issuer:                     issuer,
103			Storage:                    stor,
104			SkipApprovalScreen:         true,
105			SupportedResponseTypes:     []string{"code"},
106			ContinueOnConnectorFailure: true,
107			Logger:                     logger,
108			PrometheusRegistry:         prometheus.NewRegistry(),
109			RotateKeysAfter:            6 * time.Hour,
110			IDTokensValidFor:           24 * time.Hour,
111			RefreshTokenPolicy:         refreshPolicy,
112			Web: server.WebConfig{
113				Issuer: "NetBird",
114			},
115		}
116	
117		dexSrv, err := server.NewServer(ctx, dexConfig)
118		if err != nil {
119			stor.Close()
120			return nil, fmt.Errorf("failed to create dex server: %w", err)
121		}
122	
123		return &Provider{
124			config:    config,
125			dexServer: dexSrv,
126			storage:   stor,
127			logger:    logger,
128		}, nil
129	}
130	
131	// NewProviderFromYAML creates and initializes the Dex server from a YAMLConfig
132	func NewProviderFromYAML(ctx context.Context, yamlConfig *YAMLConfig) (*Provider, error) {
133		// Configure log level from config, default to WARN to avoid logging sensitive data (emails)
134		logLevel := slog.LevelWarn
135		if yamlConfig.Logger.Level != "" {
136			switch strings.ToLower(yamlConfig.Logger.Level) {
137			case "debug":
138				logLevel = slog.LevelDebug
139			case "info":
140				logLevel = slog.LevelInfo
141			case "warn", "warning":
142				logLevel = slog.LevelWarn
143			case "error":
144				logLevel = slog.LevelError
145			}
146		}
147		logger := slog.New(NewLogrusHandler(logLevel))
148	
149		stor, err := yamlConfig.Storage.OpenStorage(logger)
150		if err != nil {
151			return nil, fmt.Errorf("failed to open storage: %w", err)
152		}
153	
154		if err := initializeStorage(ctx, stor, yamlConfig); err != nil {
155			stor.Close()
156			return nil, err
157		}
158	
159		dexConfig := buildDexConfig(yamlConfig, stor, logger)
160		dexConfig.RefreshTokenPolicy, err = yamlConfig.GetRefreshTokenPolicy(logger)
161		if err != nil {
162			stor.Close()
163			return nil, fmt.Errorf("failed to create refresh token policy: %w", err)
164		}
165	
166		dexSrv, err := server.NewServer(ctx, dexConfig)
167		if err != nil {
168			stor.Close()
169			return nil, fmt.Errorf("failed to create dex server: %w", err)
170		}
171	
172		return &Provider{
173			config:     &Config{Issuer: yamlConfig.Issuer, GRPCAddr: yamlConfig.GRPC.Addr},
174			yamlConfig: yamlConfig,
175			dexServer:  dexSrv,
176			storage:    stor,
177			logger:     logger,
178		}, nil
179	}
180	
181	// initializeStorage sets up connectors, passwords, and clients in storage
182	func initializeStorage(ctx context.Context, stor storage.Storage, cfg *YAMLConfig) error {
183		if cfg.EnablePasswordDB {
184			if err := ensureLocalConnector(ctx, stor); err != nil {
185				return fmt.Errorf("failed to ensure local connector: %w", err)
186			}
187		}
188		if err := ensureStaticPasswords(ctx, stor, cfg.StaticPasswords); err != nil {
189			return err
190		}
191		if err := ensureStaticClients(ctx, stor, cfg.StaticClients); err != nil {
192			return err
193		}
194		return ensureStaticConnectors(ctx, stor, cfg.StaticConnectors)
195	}
196	
197	// ensureStaticPasswords creates or updates static passwords in storage
198	func ensureStaticPasswords(ctx context.Context, stor storage.Storage, passwords []Password) error {
199		for _, pw := range passwords {
200			existing, err := stor.GetPassword(ctx, pw.Email)
201			if errors.Is(err, storage.ErrNotFound) {
202				if err := stor.CreatePassword(ctx, storage.Password(pw)); err != nil {
203					return fmt.Errorf("failed to create password for %s: %w", pw.Email, err)
204				}
205				continue
206			}
207			if err != nil {
208				return fmt.Errorf("failed to get password for %s: %w", pw.Email, err)
209			}
210			if string(existing.Hash) != string(pw.Hash) {
211				if err := stor.UpdatePassword(ctx, pw.Email, func(old storage.Password) (storage.Password, error) {
212					old.Hash = pw.Hash
213					old.Username = pw.Username
214					return old, nil
215				}); err != nil {
216					return fmt.Errorf("failed to update password for %s: %w", pw.Email, err)
217				}
218			}
219		}
220		return nil
221	}
222	
223	// ensureStaticClients creates or updates static clients in storage
224	func ensureStaticClients(ctx context.Context, stor storage.Storage, clients []storage.Client) error {
225		for _, client := range clients {
226			_, err := stor.GetClient(ctx, client.ID)
227			if errors.Is(err, storage.ErrNotFound) {
228				if err := stor.CreateClient(ctx, client); err != nil {
229					return fmt.Errorf("failed to create client %s: %w", client.ID, err)
230				}
231				continue
232			}
233			if err != nil {
234				return fmt.Errorf("failed to get client %s: %w", client.ID, err)
235			}
236			if err := stor.UpdateClient(ctx, client.ID, func(old storage.Client) (storage.Client, error) {
237				old.RedirectURIs = client.RedirectURIs
238				old.Name = client.Name
239				old.Public = client.Public
240				return old, nil
241			}); err != nil {
242				return fmt.Errorf("failed to update client %s: %w", client.ID, err)
243			}
244		}
245		return nil
246	}
247	
248	// buildDexConfig creates a server.Config with defaults applied
249	func buildDexConfig(yamlConfig *YAMLConfig, stor storage.Storage, logger *slog.Logger) server.Config {
250		cfg := yamlConfig.ToServerConfig(stor, logger)
251		cfg.PrometheusRegistry = prometheus.NewRegistry()
252		if cfg.RotateKeysAfter == 0 {
253			cfg.RotateKeysAfter = 24 * 30 * time.Hour
254		}
255		if cfg.IDTokensValidFor == 0 {
256			cfg.IDTokensValidFor = 24 * time.Hour
257		}
258		if cfg.Web.Issuer == "" {
259			cfg.Web.Issuer = "NetBird"
260		}
261		if len(cfg.SupportedResponseTypes) == 0 {
262			cfg.SupportedResponseTypes = []string{"code"}
263		}
264		cfg.ContinueOnConnectorFailure = true
265		return cfg
266	}
267	
268	// Start starts the HTTP server and optionally the gRPC API server
269	func (p *Provider) Start(_ context.Context) error {
270		p.mu.Lock()
271		defer p.mu.Unlock()
272	
273		if p.running {
274			return fmt.Errorf("already running")
275		}
276	
277		// Determine listen address from config
278		var addr string
279		if p.yamlConfig != nil {
280			addr = p.yamlConfig.Web.HTTP
281			if addr == "" {
282				addr = p.yamlConfig.Web.HTTPS
283			}
284		} else if p.config != nil && p.config.Port > 0 {
285			addr = fmt.Sprintf(":%d", p.config.Port)
286		}
287		if addr == "" {
288			return fmt.Errorf("no listen address configured")
289		}
290	
291		listener, err := net.Listen("tcp", addr)
292		if err != nil {
293			return fmt.Errorf("failed to listen on %s: %w", addr, err)
294		}
295		p.listener = listener
296	
297		// Mount Dex at /oauth2/ path for reverse proxy compatibility
298		// Don't strip the prefix - Dex's issuer includes /oauth2 so it expects the full path
299		mux := http.NewServeMux()
300		mux.Handle("/oauth2/", p.dexServer)
301	
302		p.httpServer = &http.Server{Handler: mux}
303		p.running = true
304	
305		go func() {
306			if err := p.httpServer.Serve(listener); err != nil && err != http.ErrServerClosed {
307				p.logger.Error("http server error", "error", err)
308			}
309		}()
310	
311		// Start gRPC API server if configured
312		if p.config.GRPCAddr != "" {
313			if err := p.startGRPCServer(); err != nil {
314				// Clean up HTTP server on failure
315				_ = p.httpServer.Close()
316				_ = p.listener.Close()
317				return fmt.Errorf("failed to start gRPC server: %w", err)
318			}
319		}
320	
321		p.logger.Info("HTTP server started", "addr", addr)
322		return nil
323	}
324	
325	// startGRPCServer starts the gRPC API server using Dex's built-in API
326	func (p *Provider) startGRPCServer() error {
327		grpcListener, err := net.Listen("tcp", p.config.GRPCAddr)
328		if err != nil {
329			return fmt.Errorf("failed to listen on %s: %w", p.config.GRPCAddr, err)
330		}
331		p.grpcListener = grpcListener
332	
333		p.grpcServer = grpc.NewServer()
334		// Use Dex's built-in API server implementation
335		// server.NewAPI(storage, logger, version, dexServer)
336		dexapi.RegisterDexServer(p.grpcServer, server.NewAPI(p.storage, p.logger, "netbird-dex", p.dexServer))
337	
338		go func() {
339			if err := p.grpcServer.Serve(grpcListener); err != nil {
340				p.logger.Error("grpc server error", "error", err)
341			}
342		}()
343	
344		p.logger.Info("gRPC API server started", "addr", p.config.GRPCAddr)
345		return nil
346	}
347	
348	// Stop gracefully shuts down
349	func (p *Provider) Stop(ctx context.Context) error {
350		p.mu.Lock()
351		defer p.mu.Unlock()
352	
353		if !p.running {
354			return nil
355		}
356	
357		var errs []error
358	
359		// Stop gRPC server first
360		if p.grpcServer != nil {
361			p.grpcServer.GracefulStop()
362			p.grpcServer = nil
363		}
364		if p.grpcListener != nil {
365			p.grpcListener.Close()
366			p.grpcListener = nil
367		}
368	
369		if p.httpServer != nil {
370			if err := p.httpServer.Shutdown(ctx); err != nil {
371				errs = append(errs, err)
372			}
373		}
374	
375		// Explicitly close listener as fallback (Shutdown should do this, but be safe)
376		if p.listener != nil {
377			if err := p.listener.Close(); err != nil {
378				// Ignore "use of closed network connection" - expected after Shutdown
379				if !strings.Contains(err.Error(), "use of closed") {
380					errs = append(errs, err)
381				}
382			}
383			p.listener = nil
384		}
385	
386		if p.storage != nil {
387			if err := p.storage.Close(); err != nil {
388				errs = append(errs, err)
389			}
390		}
391	
392		p.httpServer = nil
393		p.running = false
394	
395		if len(errs) > 0 {
396			return fmt.Errorf("shutdown errors: %v", errs)
397		}
398		return nil
399	}
400	
401	// EnsureDefaultClients creates dashboard and CLI OAuth clients
402	// Uses Dex's storage.Client directly - no custom wrappers
403	func (p *Provider) EnsureDefaultClients(ctx context.Context, dashboardURIs, cliURIs []string) error {
404		clients := []storage.Client{
405			{
406				ID:           "netbird-dashboard",
407				Name:         "NetBird Dashboard",
408				RedirectURIs: dashboardURIs,
409				Public:       true,
410			},
411			{
412				ID:           "netbird-cli",
413				Name:         "NetBird CLI",
414				RedirectURIs: cliURIs,
415				Public:       true,
416			},
417		}
418	
419		for _, client := range clients {
420			_, err := p.storage.GetClient(ctx, client.ID)
421			if err == storage.ErrNotFound {
422				if err := p.storage.CreateClient(ctx, client); err != nil {
423					return fmt.Errorf("failed to create client %s: %w", client.ID, err)
424				}
425				continue
426			}
427			if err != nil {
428				return fmt.Errorf("failed to get client %s: %w", client.ID, err)
429			}
430			// Update if exists
431			if err := p.storage.UpdateClient(ctx, client.ID, func(old storage.Client) (storage.Client, error) {
432				old.RedirectURIs = client.RedirectURIs
433				return old, nil
434			}); err != nil {
435				return fmt.Errorf("failed to update client %s: %w", client.ID, err)
436			}
437		}
438	
439		p.logger.Info("default OIDC clients ensured")
440		return nil
441	}
442	
443	// Storage returns the underlying Dex storage for direct access
444	// Users can use storage.Client, storage.Password, storage.Connector directly
445	func (p *Provider) Storage() storage.Storage {
446		return p.storage
447	}
448	
449	// Handler returns the Dex server as an http.Handler for embedding in another server.
450	// The handler expects requests with path prefix "/oauth2/".
451	func (p *Provider) Handler() http.Handler {
452		return p.dexServer
453	}
454	
455	// CreateUser creates a new user with the given email, username, and password.
456	// Returns the encoded user ID in Dex's format (base64-encoded protobuf with connector ID).
457	func (p *Provider) CreateUser(ctx context.Context, email, username, password string) (string, error) {
458		hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
459		if err != nil {
460			return "", fmt.Errorf("failed to hash password: %w", err)
461		}
462	
463		userID := uuid.New().String()
464		err = p.storage.CreatePassword(ctx, storage.Password{
465			Email:    email,
466			Username: username,
467			UserID:   userID,
468			Hash:     hash,
469		})
470		if err != nil {
471			return "", err
472		}
473	
474		// Encode the user ID in Dex's format: base64(protobuf{user_id, connector_id})
475		// This matches the format Dex uses in JWT tokens
476		encodedID := EncodeDexUserID(userID, "local")
477		return encodedID, nil
478	}
479	
480	// EncodeDexUserID encodes user ID and connector ID into Dex's base64-encoded protobuf format.
481	// Dex uses this format for the 'sub' claim in JWT tokens.
482	// Format: base64(protobuf message with field 1 = user_id, field 2 = connector_id)
483	func EncodeDexUserID(userID, connectorID string) string {
484		// Manually encode protobuf: field 1 (user_id) and field 2 (connector_id)
485		// Wire type 2 (length-delimited) for strings
486		var buf []byte
487	
488		// Field 1: user_id (tag = 0x0a = field 1, wire type 2)
489		buf = append(buf, 0x0a)
490		buf = append(buf, byte(len(userID)))
491		buf = append(buf, []byte(userID)...)
492	
493		// Field 2: connector_id (tag = 0x12 = field 2, wire type 2)
494		buf = append(buf, 0x12)
495		buf = append(buf, byte(len(connectorID)))
496		buf = append(buf, []byte(connectorID)...)
497	
498		return base64.RawStdEncoding.EncodeToString(buf)
499	}
500	
501	// DecodeDexUserID decodes Dex's base64-encoded user ID back to the raw user ID and connector ID.
502	func DecodeDexUserID(encodedID string) (userID, connectorID string, err error) {
503		// Try RawStdEncoding first, then StdEncoding (with padding)
504		buf, err := base64.RawStdEncoding.DecodeString(encodedID)
505		if err != nil {
506			buf, err = base64.StdEncoding.DecodeString(encodedID)
507			if err != nil {
508				return "", "", fmt.Errorf("failed to decode base64: %w", err)
509			}
510		}
511	
512		// Parse protobuf manually
513		i := 0
514		for i < len(buf) {
515			if i >= len(buf) {
516				break
517			}
518			tag := buf[i]
519			i++
520	
521			fieldNum := tag >> 3
522			wireType := tag & 0x07
523	
524			if wireType != 2 { // We only expect length-delimited strings
525				return "", "", fmt.Errorf("unexpected wire type %d", wireType)
526			}
527	
528			if i >= len(buf) {
529				return "", "", fmt.Errorf("truncated message")
530			}
531			length := int(buf[i])
532			i++
533	
534			if i+length > len(buf) {
535				return "", "", fmt.Errorf("truncated string field")
536			}
537			value := string(buf[i : i+length])
538			i += length
539	
540			switch fieldNum {
541			case 1:
542				userID = value
543			case 2:
544				connectorID = value
545			}
546		}
547	
548		return userID, connectorID, nil
549	}
550	
551	// GetUser returns a user by email
552	func (p *Provider) GetUser(ctx context.Context, email string) (storage.Password, error) {
553		return p.storage.GetPassword(ctx, email)
554	}
555	
556	// GetUserByID returns a user by user ID.
557	// The userID can be either an encoded Dex ID (base64 protobuf) or a raw UUID.
558	// Note: This requires iterating through all users since dex storage doesn't index by userID.
559	func (p *Provider) GetUserByID(ctx context.Context, userID string) (storage.Password, error) {
560		// Try to decode the user ID in case it's encoded
561		rawUserID, _, err := DecodeDexUserID(userID)
562		if err != nil {
563			// If decoding fails, assume it's already a raw UUID
564			rawUserID = userID
565		}
566	
567		users, err := p.storage.ListPasswords(ctx)
568		if err != nil {
569			return storage.Password{}, fmt.Errorf("failed to list users: %w", err)
570		}
571		for _, user := range users {
572			if user.UserID == rawUserID {
573				return user, nil
574			}
575		}
576		return storage.Password{}, storage.ErrNotFound
577	}
578	
579	// DeleteUser removes a user by email
580	func (p *Provider) DeleteUser(ctx context.Context, email string) error {
581		return p.storage.DeletePassword(ctx, email)
582	}
583	
584	// ListUsers returns all users
585	func (p *Provider) ListUsers(ctx context.Context) ([]storage.Password, error) {
586		return p.storage.ListPasswords(ctx)
587	}
588	
589	// UpdateUserPassword updates the password for a user identified by userID.
590	// The userID can be either an encoded Dex ID (base64 protobuf) or a raw UUID.
591	// It verifies the current password before updating.
592	func (p *Provider) UpdateUserPassword(ctx context.Context, userID string, oldPassword, newPassword string) error {
593		// Get the user by ID to find their email
594		user, err := p.GetUserByID(ctx, userID)
595		if err != nil {
596			return fmt.Errorf("failed to get user: %w", err)
597		}
598	
599		// Verify old password
600		if err := bcrypt.CompareHashAndPassword(user.Hash, []byte(oldPassword)); err != nil {
601			return fmt.Errorf("current password is incorrect")
602		}
603	
604		// Hash the new password
605		newHash, err := bcrypt.GenerateFromPassword([]byte(newPassword), bcrypt.DefaultCost)
606		if err != nil {
607			return fmt.Errorf("failed to hash new password: %w", err)
608		}
609	
610		// Update the password in storage
611		err = p.storage.UpdatePassword(ctx, user.Email, func(old storage.Password) (storage.Password, error) {
612			old.Hash = newHash
613			return old, nil
614		})
615		if err != nil {
616			return fmt.Errorf("failed to update password: %w", err)
617		}
618	
619		return nil
620	}
621	
622	// GetIssuer returns the OIDC issuer URL.
623	func (p *Provider) GetIssuer() string {
624		if p.config == nil {
625			return ""
626		}
627		issuer := strings.TrimSuffix(p.config.Issuer, "/")
628		if !strings.HasSuffix(issuer, "/oauth2") {
629			issuer += "/oauth2"
630		}
631		return issuer
632	}
633	
634	// GetKeysLocation returns the JWKS endpoint URL for token validation.
635	func (p *Provider) GetKeysLocation() string {
636		issuer := p.GetIssuer()
637		if issuer == "" {
638			return ""
639		}
640		return issuer + "/keys"
641	}
642	
643	// GetTokenEndpoint returns the OAuth2 token endpoint URL.
644	func (p *Provider) GetTokenEndpoint() string {
645		issuer := p.GetIssuer()
646		if issuer == "" {
647			return ""
648		}
649		return issuer + "/token"
650	}
651	
652	// GetDeviceAuthEndpoint returns the OAuth2 device authorization endpoint URL.
653	func (p *Provider) GetDeviceAuthEndpoint() string {
654		issuer := p.GetIssuer()
655		if issuer == "" {
656			return ""
657		}
658		return issuer + "/device/code"
659	}
660	
661	// GetAuthorizationEndpoint returns the OAuth2 authorization endpoint URL.
662	func (p *Provider) GetAuthorizationEndpoint() string {
663		issuer := p.GetIssuer()
664		if issuer == "" {
665			return ""
666		}
667		return issuer + "/auth"
668	}
