// GetAuthorizationEndpoint returns the OAuth2 authorization endpoint URL.
func (p *Provider) GetAuthorizationEndpoint() string {
	issuer := p.GetIssuer()
	if issuer == "" {
		return ""
	}
	return issuer + "/auth"
}

// GetJWKS reads signing keys directly from Dex storage and returns them as Jwks.
// This avoids HTTP round-trips when the embedded IDP is co-located with the management server.
func (p *Provider) GetJWKS(ctx context.Context) (*nbjwt.Jwks, error) {
	keys, err := p.storage.GetKeys(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to get keys from dex storage: %w", err)
	}

	jwks := &nbjwt.Jwks{}

	if keys.SigningKeyPub != nil {
		jwk, err := joseKeyToJSONWebKey(keys.SigningKeyPub)
		if err == nil {
			jwks.Keys = append(jwks.Keys, jwk)
		}
	}

	for _, vk := range keys.VerificationKeys {
		if vk.PublicKey != nil {
			jwk, err := joseKeyToJSONWebKey(vk.PublicKey)
			if err == nil {
				jwks.Keys = append(jwks.Keys, jwk)
			}
		}
	}

	if !keys.NextRotation.IsZero() {
		jwks.ExpiresInTime = keys.NextRotation
	} else {
		jwks.ExpiresInTime = time.Now().Add(1 * time.Hour)
	}

	return jwks, nil
}

// joseKeyToJSONWebKey converts a go-jose JSONWebKey to our JSONWebKey representation.
func joseKeyToJSONWebKey(key *jose.JSONWebKey) (nbjwt.JSONWebKey, error) {
	jwk := nbjwt.JSONWebKey{
		Kid: key.KeyID,
		Use: key.Use,
	}

	switch pub := key.Key.(type) {
	case *rsa.PublicKey:
		jwk.Kty = "RSA"
		jwk.N = base64.RawURLEncoding.EncodeToString(pub.N.Bytes())
		jwk.E = base64.RawURLEncoding.EncodeToString(big.NewInt(int64(pub.E)).Bytes())
	case *ecdsa.PublicKey:
		jwk.Kty = "EC"
		jwk.X = base64.RawURLEncoding.EncodeToString(pub.X.Bytes())
		jwk.Y = base64.RawURLEncoding.EncodeToString(pub.Y.Bytes())
		jwk.Crv = pub.Curve.Params().Name
	default:
		return jwk, fmt.Errorf("unsupported key type: %T", key.Key)
	}

	return jwk, nil
}

