func (v *Validator) refreshKeys(ctx context.Context) {
	v.lock.Lock()
	defer v.lock.Unlock()

	refreshedKeys, err := getPemKeys(v.keysLocation)
	if err != nil {
		log.WithContext(ctx).Debugf("cannot get JSONWebKey: %v, falling back to old keys", err)
